import React from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const TestLogin = () => {
  const navigate = useNavigate();
  const API_URL = 'http://localhost:3000/api';

  const handleTestLogin = async (role) => {
    try {
      const email = `test_${role}@example.com`;
      const password = 'test123';
      
      // Шаг 1: Пробуем зарегистрироваться (если пользователь уже существует - игнорируем ошибку)
      try {
        await axios.post(`${API_URL}/auth/register`, {
          email: email,
          password: password,
          first_name: role === 'admin' ? 'Тест' : (role === 'seller' ? 'Продавец' : 'Пользователь'),
          last_name: role === 'admin' ? 'Админ' : (role === 'seller' ? 'Продавцов' : 'Пользователей'),
          age: 25,
          role: role
        }, {
          headers: {
            'Content-Type': 'application/json',
          }
        });
        console.log(`✅ Пользователь ${role} зарегистрирован`);
      } catch (registerError) {
        // Если пользователь уже существует (409) или другая ошибка - продолжаем
        console.log(`ℹ️ Пользователь ${role} уже существует или ошибка регистрации:`, registerError.message);
      }

      // Шаг 2: Входим в систему
      console.log('🔄 Выполняем вход...');
      const response = await axios.post(`${API_URL}/auth/login`, {
        email: email,
        password: password
      }, {
        headers: {
          'Content-Type': 'application/json',
        }
      });

      const { accessToken, user } = response.data;
      
      console.log('✅ Успешный вход!', user);
      
      // Сохраняем токен
      localStorage.setItem('accessToken', accessToken);
      
      // Перенаправляем на главную
      navigate('/products');
      
      // Перезагружаем страницу для обновления контекста
      setTimeout(() => {
        window.location.reload();
      }, 100);
      
    } catch (error) {
      console.error('❌ Test login error:', error);
      
      if (error.response) {
        // Сервер ответил ошибкой
        alert(`Ошибка ${error.response.status}: ${error.response.data.error || error.response.data.message}`);
      } else if (error.request) {
        // Запрос был отправлен, но ответа нет
        alert('Сервер не отвечает. Убедитесь, что бэкенд запущен на http://localhost:3000');
      } else {
        // Другая ошибка
        alert('Ошибка при тестовом входе: ' + error.message);
      }
    }
  };

  return (
    <div style={styles.container}>
      <h3 style={styles.title}>🔧 Тестовый вход</h3>
      <div style={styles.buttons}>
        <button 
          onClick={() => handleTestLogin('user')}
          style={styles.userButton}
          title="Обычный пользователь (только просмотр)"
        >
          👤 Войти как Пользователь
        </button>
        <button 
          onClick={() => handleTestLogin('seller')}
          style={styles.sellerButton}
          title="Продавец (добавление и редактирование товаров)"
        >
          💼 Войти как Продавец
        </button>
        <button 
          onClick={() => handleTestLogin('admin')}
          style={styles.adminButton}
          title="Администратор (полные права)"
        >
          👑 Войти как Администратор
        </button>
      </div>
    </div>
  );
};

const styles = {
  container: {
    position: 'fixed',
    bottom: '20px',
    right: '20px',
    backgroundColor: 'white',
    padding: '20px',
    borderRadius: '8px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
    zIndex: 1000,
    minWidth: '250px'
  },
  title: {
    margin: '0 0 15px 0',
    fontSize: '16px',
    color: '#333',
    textAlign: 'center',
    fontWeight: 'bold'
  },
  buttons: {
    display: 'flex',
    flexDirection: 'column',
    gap: '10px'
  },
  userButton: {
    padding: '12px 15px',
    backgroundColor: '#6c757d',
    color: 'white',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    transition: 'background-color 0.2s'
  },
  sellerButton: {
    padding: '12px 15px',
    backgroundColor: '#ffc107',
    color: '#333',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: 'bold',
    transition: 'background-color 0.2s'
  },
  adminButton: {
    padding: '12px 15px',
    backgroundColor: '#dc3545',
    color: 'white',
    border: 'none',
    borderRadius: '4px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: 'bold',
    transition: 'background-color 0.2s'
  }
};

export default TestLogin;
